     /// "HTMLParser".Humanize() => "HTML parser"
     /// </code>
     /// </example>
     public static string Humanize(this string input)
     {
         if (string.IsNullOrWhiteSpace(input))
         {
             return input;
         }

         // Handle already-spaced strings
         if (FreestandingSpacingCharRegex().IsMatch(input))
